SET FOREIGN_KEY_CHECKS=0;



CREATE TABLE `customers` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `customer_type` enum('private','company') DEFAULT 'private',
  `first_name` varchar(50) NOT NULL,
  `last_name` varchar(50) NOT NULL,
  `ico` varchar(20) DEFAULT NULL,
  `dic` varchar(20) DEFAULT NULL,
  `company` varchar(100) DEFAULT NULL,
  `phone` varchar(20) DEFAULT NULL,
  `email` varchar(100) DEFAULT NULL,
  `address` text DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `old_user_id` int(11) DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=3298 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;




CREATE TABLE `device_brands` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `brand_name` varchar(100) NOT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `brand_name` (`brand_name`)
) ENGINE=InnoDB AUTO_INCREMENT=63 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;




CREATE TABLE `inventory` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `part_name` varchar(100) NOT NULL,
  `sku` varchar(50) DEFAULT NULL,
  `quantity` int(11) DEFAULT 0,
  `cost_price` decimal(10,2) DEFAULT NULL,
  `sale_price` decimal(10,2) DEFAULT NULL,
  `min_stock` int(11) DEFAULT 5,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=3 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;




CREATE TABLE `invoice_items` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `invoice_id` int(11) NOT NULL,
  `item_name` varchar(255) NOT NULL,
  `quantity` decimal(10,2) DEFAULT 1.00,
  `unit` varchar(10) DEFAULT 'ks',
  `price` decimal(15,2) NOT NULL,
  `vat_rate` decimal(5,2) DEFAULT 21.00,
  PRIMARY KEY (`id`),
  KEY `invoice_id` (`invoice_id`),
  CONSTRAINT `invoice_items_ibfk_1` FOREIGN KEY (`invoice_id`) REFERENCES `invoices` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=10 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;




CREATE TABLE `invoices` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `invoice_number` varchar(50) NOT NULL,
  `variable_symbol` varchar(50) DEFAULT NULL,
  `order_id` int(11) DEFAULT NULL,
  `customer_id` int(11) NOT NULL,
  `date_issue` date NOT NULL,
  `date_tax` date NOT NULL,
  `date_due` date NOT NULL,
  `total_amount` decimal(15,2) NOT NULL,
  `is_vat_payer` tinyint(1) DEFAULT 0,
  `vat_amount` decimal(15,2) DEFAULT 0.00,
  `currency` varchar(10) DEFAULT 'Kč',
  `status` enum('draft','issued','paid','overdue','cancelled') DEFAULT 'issued',
  `payment_method` varchar(50) DEFAULT 'bank_transfer',
  `payment_date` date DEFAULT NULL,
  `pdf_path` varchar(255) DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `invoice_type` enum('invoice','credit_note') DEFAULT 'invoice',
  `parent_id` int(11) DEFAULT NULL,
  `notes` text DEFAULT NULL,
  `cust_name_override` varchar(255) DEFAULT NULL,
  `cust_address_override` text DEFAULT NULL,
  `cust_ico_override` varchar(20) DEFAULT NULL,
  `cust_dic_override` varchar(20) DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `invoice_number` (`invoice_number`),
  KEY `order_id` (`order_id`),
  KEY `customer_id` (`customer_id`),
  KEY `fk_invoice_parent` (`parent_id`),
  CONSTRAINT `fk_invoice_parent` FOREIGN KEY (`parent_id`) REFERENCES `invoices` (`id`) ON DELETE SET NULL,
  CONSTRAINT `invoices_ibfk_1` FOREIGN KEY (`order_id`) REFERENCES `orders` (`id`) ON DELETE SET NULL,
  CONSTRAINT `invoices_ibfk_2` FOREIGN KEY (`customer_id`) REFERENCES `customers` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;




CREATE TABLE `order_attachments` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `order_id` int(11) NOT NULL,
  `file_path` varchar(255) NOT NULL,
  `file_type` varchar(50) DEFAULT NULL,
  `file_name` varchar(255) DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`id`),
  KEY `order_id` (`order_id`),
  CONSTRAINT `order_attachments_ibfk_1` FOREIGN KEY (`order_id`) REFERENCES `orders` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=7 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;




CREATE TABLE `order_items` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `order_id` int(11) NOT NULL,
  `inventory_id` int(11) NOT NULL,
  `quantity` int(11) DEFAULT 1,
  `price` decimal(10,2) DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `order_id` (`order_id`),
  KEY `inventory_id` (`inventory_id`),
  CONSTRAINT `order_items_ibfk_1` FOREIGN KEY (`order_id`) REFERENCES `orders` (`id`),
  CONSTRAINT `order_items_ibfk_2` FOREIGN KEY (`inventory_id`) REFERENCES `inventory` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=3 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;




CREATE TABLE `orders` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `customer_id` int(11) NOT NULL,
  `device_type` enum('Phone','Notebook','PC','Tablet','HDD','Computer','Other') NOT NULL,
  `order_type` enum('Non-Warranty','Warranty') DEFAULT 'Non-Warranty',
  `device_model` varchar(100) NOT NULL,
  `device_brand` varchar(100) DEFAULT NULL,
  `serial_number` varchar(100) DEFAULT NULL,
  `serial_number_2` varchar(100) DEFAULT NULL,
  `appearance` text DEFAULT NULL,
  `pin_code` varchar(50) DEFAULT NULL,
  `priority` enum('Normal','High') DEFAULT 'Normal',
  `problem_description` text DEFAULT NULL,
  `technician_notes` text DEFAULT NULL,
  `estimated_cost` decimal(10,2) DEFAULT NULL,
  `final_cost` decimal(10,2) DEFAULT NULL,
  `extra_expenses` decimal(10,2) DEFAULT 0.00,
  `status` enum('New','In Progress','Waiting for Parts','Completed','Collected','Cancelled') DEFAULT 'New',
  `technician_id` int(11) DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  `old_quitt_id` int(11) DEFAULT NULL,
  `shipping_method` varchar(50) DEFAULT NULL,
  `shipping_tracking` varchar(100) DEFAULT NULL,
  `shipping_date` datetime DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `customer_id` (`customer_id`),
  CONSTRAINT `orders_ibfk_1` FOREIGN KEY (`customer_id`) REFERENCES `customers` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=10620 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;




CREATE TABLE `system_settings` (
  `setting_key` varchar(50) NOT NULL,
  `setting_value` text DEFAULT NULL,
  PRIMARY KEY (`setting_key`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;




CREATE TABLE `tech_permissions` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `technician_id` int(11) NOT NULL,
  `permission` varchar(50) NOT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`id`),
  UNIQUE KEY `unique_perm` (`technician_id`,`permission`),
  CONSTRAINT `tech_permissions_ibfk_1` FOREIGN KEY (`technician_id`) REFERENCES `technicians` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COLLATE=utf8_general_ci;




CREATE TABLE `technicians` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `name` varchar(100) NOT NULL,
  `username` varchar(50) DEFAULT NULL,
  `password` varchar(255) DEFAULT NULL,
  `phone` varchar(20) DEFAULT NULL,
  `email` varchar(100) DEFAULT NULL,
  `telegram_id` varchar(50) DEFAULT NULL,
  `specialization` varchar(100) DEFAULT NULL,
  `is_active` tinyint(1) DEFAULT 1,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `last_seen` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `username` (`username`)
) ENGINE=InnoDB AUTO_INCREMENT=13 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;




CREATE TABLE `temp_brands` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `brandname` varchar(75) NOT NULL,
  `contacts` varchar(150) NOT NULL,
  `email` varchar(75) NOT NULL,
  `phone` varchar(50) NOT NULL,
  `allow_authoriz` tinyint(1) NOT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=42 DEFAULT CHARSET=utf8 COLLATE=utf8_general_ci;




CREATE TABLE `temp_quitt` (
  `id_quitt` int(11) NOT NULL AUTO_INCREMENT,
  `id_sc` tinyint(1) NOT NULL,
  `user_id` int(11) NOT NULL,
  `id_device` int(1) NOT NULL,
  `id_brand` int(1) NOT NULL,
  `model` varchar(50) NOT NULL,
  `serial_number` varchar(50) NOT NULL COMMENT 'Серийный номер',
  `product_code` varchar(50) NOT NULL COMMENT 'Продуктовый код',
  `date_sale` date NOT NULL COMMENT 'Дата продажи',
  `defect` varchar(500) NOT NULL COMMENT 'Неисправность',
  `view` varchar(500) NOT NULL COMMENT 'Внешний вид',
  `completeness` varchar(500) NOT NULL COMMENT 'Комплектность',
  `date_receipt` date NOT NULL COMMENT 'Дата приемки',
  `date_end` date NOT NULL COMMENT 'Дата окончания',
  `date_issue` date NOT NULL COMMENT 'Дата выдачи',
  `id_status` tinyint(1) NOT NULL,
  `id_repair_type` tinyint(1) NOT NULL,
  `id_engineer` tinyint(5) NOT NULL,
  `id_manager` tinyint(1) NOT NULL,
  `notes` varchar(700) NOT NULL COMMENT 'Примечания',
  `urgent` tinyint(1) NOT NULL,
  `individual_cost` decimal(16,0) NOT NULL,
  `full_cost` decimal(16,0) NOT NULL,
  `id_avtoriz_cost` int(1) NOT NULL,
  `date_email_notific` date NOT NULL COMMENT 'дата email уведомления',
  `date_sms_notific` date NOT NULL COMMENT 'дата sms уведомления',
  PRIMARY KEY (`id_quitt`)
) ENGINE=InnoDB AUTO_INCREMENT=10631 DEFAULT CHARSET=utf8 COLLATE=utf8_general_ci;




CREATE TABLE `users` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `username` varchar(50) NOT NULL,
  `password` varchar(255) NOT NULL,
  `full_name` varchar(100) DEFAULT NULL,
  `role` enum('admin','technician') DEFAULT 'technician',
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`id`),
  UNIQUE KEY `username` (`username`)
) ENGINE=InnoDB AUTO_INCREMENT=4 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;



